import { useState, useCallback } from 'react';

import constFlaskURL from '../../consts/constFlaskURL'

const [tableData, setTableData] = useState([]);

export const fetchTableData = useCallback(async (endpoint) => {
    setLoading(true);

    try {
        const response = await constFlaskURL.get(endpoint);

        if (response.status === 200) {
            setTableData(Array.isArray(response.data) ? response.data : [response.data]);
        }
    } catch (err) {
        console.log(err);
    } finally {
        setLoading(false);
    }
}, []);
